package middleware

import (
    "net/http"
    "os"
    "time"
)

var logFile *os.File

func init() {
    f, err := os.OpenFile("/var/log/api.log", os.O_APPEND|os.O_WRONLY, 0644)
    if err != nil {
        panic(err)
    }
    logFile = f
}

func LoggingMiddleware(next http.Handler) http.Handler {
    return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
        start := time.Now()
        next.ServeHTTP(w, r)
        elapsed := time.Since(start)
        logEntry := fmt.Sprintf("[%s] %s %s %v\n", time.Now().Format(time.RFC3339), r.Method, r.URL.Path, elapsed)
        // BUG: 同步磁盘写入，无 buffer
        logFile.WriteString(logEntry)
    })
}
